Add-Type -AssemblyName PresentationFramework

# Function to find and modify the window
function Set-ResizableWindow {
    param (
        [string]$Title
    )

    # Find the window by its title
    $window = Get-Process | ForEach-Object {
        try {
            [Windows.Window]::FindWindow($null, $_.MainWindowTitle)
        } catch {
            $null
        }
    } | Where-Object { $_ -and $_.MainWindowTitle -eq $Title }

    if ($window) {
        # Set the ResizeMode property to make the window resizable
        $window.ResizeMode = 'CanResize'
        Write-Host "Window titled '$Title' is now resizable."
    } else {
        Write-Host "No window found with the title '$Title'."
    }
}

